// Masoretic to Septuagint numbering differences:
// MT 9-10 = LXX 9 (combined)
// MT 11-113 = LXX 10-112 (offset by 1)
// MT 114-115 = LXX 113 (combined)
// MT 116 = LXX 114-115 (split)
// MT 117-146 = LXX 116-145 (offset by 1)
// MT 147 = LXX 146-147 (split)
// MT 148-150 = LXX 148-150 (same)

function getPsalmByNumber(num, numbering = 'masoretic') {
    if (numbering === 'masoretic') {
        return PSALMS.find(p => p.number === num);
    } else {
        // For Septuagint, we show the same psalms but with LXX numbering displayed
        return PSALMS.find(p => p.number === num);
    }
}

function getAllPsalms() {
    return PSALMS;
}
